# Electric Border

Canvas-based animated wrapper component that renders a chaotic Perlin FBM noise border around any content, with configurable color, speed, and chaos level.

## Use when
- Drawing attention to a CTA button or card with an eye-catching electric border effect.
- Adding a playful, high-energy frame to a product showcase or feature highlight.
- Wrapping any UI element with a glowing animated border on a dark background.

## Stack
- Framework: react
- Libraries: (none)

## Install
```bash
# No additional packages required
```

## Component — electric-border.tsx
```tsx
import React, { useEffect, useRef, useCallback, CSSProperties, ReactNode } from 'react';

function hexToRgba(hex: string, alpha: number = 1): string {
  if (!hex) return `rgba(0,0,0,${alpha})`;
  let h = hex.replace('#', '');
  if (h.length === 3) h = h.split('').map(c => c + c).join('');
  const int = parseInt(h, 16);
  const r = (int >> 16) & 255; const g = (int >> 8) & 255; const b = int & 255;
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
}

interface ElectricBorderProps {
  children?: ReactNode;
  color?: string;
  speed?: number;
  chaos?: number;
  borderRadius?: number;
  className?: string;
  style?: CSSProperties;
}

const ElectricBorder: React.FC<ElectricBorderProps> = ({
  children,
  color = '#5227FF',
  speed = 1,
  chaos = 0.12,
  borderRadius = 24,
  className,
  style
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const animationRef = useRef<number | null>(null);
  const timeRef = useRef(0);
  const lastFrameTimeRef = useRef(0);

  const random = useCallback((x: number): number => (Math.sin(x * 12.9898) * 43758.5453) % 1, []);

  const noise2D = useCallback((x: number, y: number): number => {
    const i = Math.floor(x); const j = Math.floor(y);
    const fx = x - i; const fy = y - j;
    const a = random(i + j * 57); const b = random(i + 1 + j * 57);
    const c = random(i + (j + 1) * 57); const d = random(i + 1 + (j + 1) * 57);
    const ux = fx * fx * (3.0 - 2.0 * fx); const uy = fy * fy * (3.0 - 2.0 * fy);
    return a * (1 - ux) * (1 - uy) + b * ux * (1 - uy) + c * (1 - ux) * uy + d * ux * uy;
  }, [random]);

  const octavedNoise = useCallback((
    x: number, octaves: number, lacunarity: number, gain: number,
    baseAmplitude: number, baseFrequency: number, time: number, seed: number, baseFlatness: number
  ): number => {
    let y = 0; let amplitude = baseAmplitude; let frequency = baseFrequency;
    for (let i = 0; i < octaves; i++) {
      let octaveAmplitude = amplitude;
      if (i === 0) octaveAmplitude *= baseFlatness;
      y += octaveAmplitude * noise2D(frequency * x + seed * 100, time * frequency * 0.3);
      frequency *= lacunarity; amplitude *= gain;
    }
    return y;
  }, [noise2D]);

  const getCornerPoint = useCallback((
    centerX: number, centerY: number, radius: number,
    startAngle: number, arcLength: number, progress: number
  ): { x: number; y: number } => {
    const angle = startAngle + progress * arcLength;
    return { x: centerX + radius * Math.cos(angle), y: centerY + radius * Math.sin(angle) };
  }, []);

  const getRoundedRectPoint = useCallback((
    t: number, left: number, top: number, width: number, height: number, radius: number
  ): { x: number; y: number } => {
    const straightWidth = width - 2 * radius; const straightHeight = height - 2 * radius;
    const cornerArc = (Math.PI * radius) / 2;
    const totalPerimeter = 2 * straightWidth + 2 * straightHeight + 4 * cornerArc;
    const distance = t * totalPerimeter;
    let accumulated = 0;
    if (distance <= accumulated + straightWidth) { const progress = (distance - accumulated) / straightWidth; return { x: left + radius + progress * straightWidth, y: top }; }
    accumulated += straightWidth;
    if (distance <= accumulated + cornerArc) { const progress = (distance - accumulated) / cornerArc; return getCornerPoint(left + width - radius, top + radius, radius, -Math.PI / 2, Math.PI / 2, progress); }
    accumulated += cornerArc;
    if (distance <= accumulated + straightHeight) { const progress = (distance - accumulated) / straightHeight; return { x: left + width, y: top + radius + progress * straightHeight }; }
    accumulated += straightHeight;
    if (distance <= accumulated + cornerArc) { const progress = (distance - accumulated) / cornerArc; return getCornerPoint(left + width - radius, top + height - radius, radius, 0, Math.PI / 2, progress); }
    accumulated += cornerArc;
    if (distance <= accumulated + straightWidth) { const progress = (distance - accumulated) / straightWidth; return { x: left + width - radius - progress * straightWidth, y: top + height }; }
    accumulated += straightWidth;
    if (distance <= accumulated + cornerArc) { const progress = (distance - accumulated) / cornerArc; return getCornerPoint(left + radius, top + height - radius, radius, Math.PI / 2, Math.PI / 2, progress); }
    accumulated += cornerArc;
    if (distance <= accumulated + straightHeight) { const progress = (distance - accumulated) / straightHeight; return { x: left, y: top + height - radius - progress * straightHeight }; }
    accumulated += straightHeight;
    const progress = (distance - accumulated) / cornerArc;
    return getCornerPoint(left + radius, top + radius, radius, Math.PI, Math.PI / 2, progress);
  }, [getCornerPoint]);

  useEffect(() => {
    const canvas = canvasRef.current; const container = containerRef.current;
    if (!canvas || !container) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const octaves = 10; const lacunarity = 1.6; const gain = 0.7;
    const amplitude = chaos; const frequency = 10; const baseFlatness = 0;
    const displacement = 60; const borderOffset = 60;
    const updateSize = () => {
      const rect = container.getBoundingClientRect();
      const width = rect.width + borderOffset * 2; const height = rect.height + borderOffset * 2;
      const dpr = Math.min(window.devicePixelRatio || 1, 2);
      canvas.width = width * dpr; canvas.height = height * dpr;
      canvas.style.width = `${width}px`; canvas.style.height = `${height}px`;
      ctx.scale(dpr, dpr);
      return { width, height };
    };
    let { width, height } = updateSize();
    const drawElectricBorder = (currentTime: number) => {
      if (!canvas || !ctx) return;
      const deltaTime = (currentTime - lastFrameTimeRef.current) / 1000;
      timeRef.current += deltaTime * speed; lastFrameTimeRef.current = currentTime;
      const dpr = Math.min(window.devicePixelRatio || 1, 2);
      ctx.setTransform(1, 0, 0, 1, 0, 0); ctx.clearRect(0, 0, canvas.width, canvas.height); ctx.scale(dpr, dpr);
      ctx.strokeStyle = color; ctx.lineWidth = 1; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      const scale = displacement; const left = borderOffset; const top = borderOffset;
      const borderWidth = width - 2 * borderOffset; const borderHeight = height - 2 * borderOffset;
      const maxRadius = Math.min(borderWidth, borderHeight) / 2;
      const radius = Math.min(borderRadius, maxRadius);
      const approximatePerimeter = 2 * (borderWidth + borderHeight) + 2 * Math.PI * radius;
      const sampleCount = Math.floor(approximatePerimeter / 2);
      ctx.beginPath();
      for (let i = 0; i <= sampleCount; i++) {
        const progress = i / sampleCount;
        const point = getRoundedRectPoint(progress, left, top, borderWidth, borderHeight, radius);
        const xNoise = octavedNoise(progress * 8, octaves, lacunarity, gain, amplitude, frequency, timeRef.current, 0, baseFlatness);
        const yNoise = octavedNoise(progress * 8, octaves, lacunarity, gain, amplitude, frequency, timeRef.current, 1, baseFlatness);
        const displacedX = point.x + xNoise * scale; const displacedY = point.y + yNoise * scale;
        if (i === 0) ctx.moveTo(displacedX, displacedY); else ctx.lineTo(displacedX, displacedY);
      }
      ctx.closePath(); ctx.stroke();
      animationRef.current = requestAnimationFrame(drawElectricBorder);
    };
    const resizeObserver = new ResizeObserver(() => { const newSize = updateSize(); width = newSize.width; height = newSize.height; });
    resizeObserver.observe(container);
    animationRef.current = requestAnimationFrame(drawElectricBorder);
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); resizeObserver.disconnect(); };
  }, [color, speed, chaos, borderRadius, octavedNoise, getRoundedRectPoint]);

  return (
    <div ref={containerRef} className={`relative overflow-visible isolate ${className ?? ''}`} style={{ '--electric-border-color': color, borderRadius, ...style } as CSSProperties}>
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none z-[2]">
        <canvas ref={canvasRef} className="block" />
      </div>
      <div className="absolute inset-0 rounded-[inherit] pointer-events-none z-0">
        <div className="absolute inset-0 rounded-[inherit] pointer-events-none" style={{ border: `2px solid ${hexToRgba(color, 0.6)}`, filter: 'blur(1px)' }} />
        <div className="absolute inset-0 rounded-[inherit] pointer-events-none" style={{ border: `2px solid ${color}`, filter: 'blur(4px)' }} />
        <div className="absolute inset-0 rounded-[inherit] pointer-events-none -z-[1] scale-110 opacity-30" style={{ filter: 'blur(32px)', background: `linear-gradient(-30deg, ${color}, transparent, ${color})` }} />
      </div>
      <div className="relative rounded-[inherit] z-[1]">{children}</div>
    </div>
  );
};

export default ElectricBorder;
```

## Demo
```tsx
import React from 'react';
import ElectricBorder from './Component';
import { Zap } from 'lucide-react';

export default function App() {
  return (
    <div className="min-h-screen bg-[#1A1A1B] text-white p-8 flex flex-col items-center justify-center font-sans gap-16">
      <ElectricBorder color="#7df9ff" speed={1.5} chaos={0.25} borderRadius={24}>
        <div className="p-8 w-64 h-64 flex flex-col items-center justify-center text-center gap-4 bg-zinc-900/80">
          <Zap size={32} className="text-[#7df9ff]" />
          <h3 className="text-xl font-bold text-[#7df9ff] tracking-wider">VOLTAGE</h3>
        </div>
      </ElectricBorder>
      <ElectricBorder color="#ff0055" speed={2} chaos={0.3} borderRadius={9999}>
        <button className="px-8 py-3 bg-zinc-900 rounded-full font-bold text-[#ff0055] tracking-widest uppercase text-sm">Critical Alert</button>
      </ElectricBorder>
    </div>
  );
}
